+  "OPENCLAW_AGENT_DIR",
+  "PI_CODING_AGENT_DIR",
+  "QIANFAN_API_KEY",
+  "SYNTHETIC_API_KEY",
+  "TOGETHER_API_KEY",
+  "VENICE_API_KEY",
+  "VLLM_API_KEY",
+  "XIAOMI_API_KEY",
+  // Avoid ambient AWS creds unintentionally enabling Bedrock discovery.
+  "AWS_ACCESS_KEY_ID",
+  "AWS_CONFIG_FILE",
+  "AWS_BEARER_TOKEN_BEDROCK",
+  "AWS_DEFAULT_REGION",
+  "AWS_PROFILE",
+  "AWS_REGION",
+  "AWS_SESSION_TOKEN",
+  "AWS_SECRET_ACCESS_KEY",
+  "AWS_SHARED_CREDENTIALS_FILE",
+];
